import { Mercenary } from '../models/Mercenary';
import { NAMED_MERCENARIES_DATA } from '../data/mercenaries';
import { JobType, JOB_DEFINITIONS } from '../models/JobClass';
import { calculateMaxHp, calculateMaxMp, createDefaultStats } from '../models/Stats';
import { GameState } from '../types';

// Random Names
const FIRST_NAMES_MALE = ['Aldric', 'Thorne', 'Cedric', 'Gareth', 'Rowan', 'Kael'];
const FIRST_NAMES_FEMALE = ['Lyra', 'Seraphina', 'Isolde', 'Mira', 'Elowen', 'Vesper'];
const LAST_NAMES = ['Ironheart', 'Stormwind', 'Blackwood', 'Swiftfoot', 'Crownguard', 'Oakenshield'];

export const generateRandomMercenary = (level: number): Mercenary => {
    const isMale = Math.random() > 0.5;
    const gender = isMale ? 'Male' : 'Female';
    const firstName = isMale 
        ? FIRST_NAMES_MALE[Math.floor(Math.random() * FIRST_NAMES_MALE.length)]
        : FIRST_NAMES_FEMALE[Math.floor(Math.random() * FIRST_NAMES_FEMALE.length)];
    const lastName = LAST_NAMES[Math.floor(Math.random() * LAST_NAMES.length)];

    // Pick Random Job
    const jobKeys = Object.values(JobType);
    const job = jobKeys[Math.floor(Math.random() * jobKeys.length)] as JobType;
    const jobDef = JOB_DEFINITIONS[job];

    // Stats generation based on Job Bias
    const stats = createDefaultStats();
    stats.strength += Math.floor(Math.random() * 5) + (jobDef.statBias.strength || 0) * level;
    stats.dexterity += Math.floor(Math.random() * 5) + (jobDef.statBias.dexterity || 0) * level;
    stats.intelligence += Math.floor(Math.random() * 5) + (jobDef.statBias.intelligence || 0) * level;
    stats.constitution += Math.floor(Math.random() * 5) + (jobDef.statBias.constitution || 0) * level;
    stats.luck += Math.floor(Math.random() * 5) + (jobDef.statBias.luck || 0) * level;

    const maxHp = calculateMaxHp(stats, level);
    const maxMp = calculateMaxMp(stats, level);

    return {
        id: `rnd_${Date.now()}_${Math.floor(Math.random()*1000)}`,
        name: `${firstName} ${lastName}`,
        gender,
        job,
        level,
        currentExp: 0,
        maxExp: level * 100,
        gold: level * 100 + Math.floor(Math.random() * 200),
        baseStats: stats,
        currentHp: maxHp,
        currentMp: maxMp,
        affinity: 0,
        visitCount: 0,
        portraitUrl: 'adventurer_wanderer_01.png' // Default placeholder
    };
};

export const getNextCustomer = (state: GameState): Mercenary => {
    const knowns = state.knownMercenaries || [];
    const roll = Math.random();

    // 1. Chance for Regular (Known) Mercenary to visit (40%)
    if (knowns.length > 0 && roll < 0.4) {
        // Pick one based on affinity weight? For now, random known.
        const returner = knowns[Math.floor(Math.random() * knowns.length)];
        // Update their current status (maybe heal them up for the visit)
        return {
            ...returner,
            currentHp: calculateMaxHp(returner.baseStats, returner.level), // Fully healed on return
            currentMp: calculateMaxMp(returner.baseStats, returner.level)
        };
    }

    // 2. Chance for New Named Mercenary (30%)
    const unknownNamed = NAMED_MERCENARIES_DATA.filter(n => !knowns.some(k => k.id === n.id));
    if (unknownNamed.length > 0 && roll < 0.7) {
        const template = unknownNamed[Math.floor(Math.random() * unknownNamed.length)];
        return {
            ...template,
            currentHp: calculateMaxHp(template.baseStats!, template.level!),
            currentMp: calculateMaxMp(template.baseStats!, template.level!),
            affinity: 0,
            visitCount: 0,
        } as Mercenary;
    }

    // 3. Random Mercenary (30% or fallback)
    return generateRandomMercenary(Math.max(1, Math.floor(state.stats.day / 5) + 1));
};
