  MORNING = 'Morning',
  AFTERNOON = 'Afternoon',
  EVENING = 'Evening',
}

export interface PlayerStats {
  gold: number;
  energy: number;
  maxEnergy: number;
  day: number;
  time: TimeOfDay;
}

export interface ForgeStatus {
  hasFurnace: boolean;
  anvilLevel: number;
  rubbleCleared: number; // 0 to 10 (fully cleared)
  isShopOpen: boolean;
}

