import React, { useState, useEffect, useRef } from 'react';
import { useGame } from '../context/GameContext';
import DialogueBox from './DialogueBox';
import { Store, Coins, PackageOpen, Heart, Shield, Zap, User, Swords } from 'lucide-react';
import { EQUIPMENT_ITEMS } from '../gameData';
import { ITEMS } from '../constants';
import { getAssetUrl } from '../utils';
import { getNextCustomer } from '../utils/mercenaryGenerator';
import { Mercenary } from '../models/Mercenary';
import { calculateMaxHp, calculateMaxMp } from '../models/Stats';

const ShopTab = () => {
  const { state, actions } = useGame();
  const { isShopOpen } = state.forge;

  // Customer State
  const [customer, setCustomer] = useState<{
    mercenary: Mercenary;
    requestType: 'RESOURCE' | 'EQUIPMENT';
    requestedId: string;
    price: number;
    dialogue: string;
  } | null>(null);

  const loopTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const getItemName = (id: string) => {
    const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
    if (eq) return eq.name;
    const res = Object.values(ITEMS).find(i => i.id === id);
    return res ? res.name : id;
  };

  const generateCustomer = () => {
    const mercenary = getNextCustomer(state);

    // Logic: What do they want?
    // Mercenaries mostly want Equipment suitable for their class?
    // For now, keep it simple randomization but use the mercenary's name
    const isResource = Math.random() < 0.3; // 30% chance for resources

    let requestedId = '';
    let price = 0;
    let dialogue = '';

    if (isResource) {
        const resources = [ITEMS.IRON_ORE, ITEMS.WOOD, ITEMS.COPPER_ORE];
        const target = resources[Math.floor(Math.random() * resources.length)];
        requestedId = target.id;
        price = Math.ceil(target.baseValue * (1.2 + Math.random() * 0.5));
        dialogue = `I need ${target.name} to repair my gear. Can you spare some?`;
    } else {
        const tier1Items = EQUIPMENT_ITEMS.filter(i => i.tier === 1);
        const target = tier1Items[Math.floor(Math.random() * tier1Items.length)];
        requestedId = target.id;
        price = Math.ceil(target.baseValue * (1.1 + Math.random() * 0.4));
        dialogue = `My ${mercenary.job.toLowerCase()} training requires a ${target.name}.`;
    }

    setCustomer({
        mercenary,
        requestType: isResource ? 'RESOURCE' : 'EQUIPMENT',
        requestedId,
        price,
        dialogue
    });
  };

  useEffect(() => {
    if (!isShopOpen) {
        setCustomer(null);
        if (loopTimerRef.current) clearTimeout(loopTimerRef.current);
        return;
    }

    if (!customer) {
        const waitTime = Math.random() * 2000 + 1000;
        loopTimerRef.current = setTimeout(() => {
            generateCustomer();
        }, waitTime);
    }

    return () => {
        if (loopTimerRef.current) clearTimeout(loopTimerRef.current);
    };
  }, [isShopOpen, customer]);

  const handleSell = () => {
      if (!customer) return;

      if (customer.requestType === 'RESOURCE') {
          actions.sellItem(customer.requestedId, 1, customer.price, undefined, customer.mercenary);
      } else {
          const matchingItem = state.inventory.find(i => 
              i.equipmentData && i.id.startsWith(customer.requestedId)
          );
          if (matchingItem) {
              actions.sellItem(matchingItem.id, 1, customer.price, matchingItem.id, customer.mercenary);
          }
      }

      setCustomer(null);
  };

  const handleRefuse = () => {
      setCustomer(null);
  };

  const handleToggleShop = () => {
      actions.toggleShop();
  };

  const hasItem = () => {
      if (!customer) return false;
      if (customer.requestType === 'RESOURCE') {
          const item = state.inventory.find(i => i.id === customer.requestedId);
          return item && item.quantity > 0;
      } else {
          return state.inventory.some(i => i.id.startsWith(customer.requestedId));
      }
  };

  // Stats for UI
  const maxHp = customer ? calculateMaxHp(customer.mercenary.baseStats, customer.mercenary.level) : 100;
  const maxMp = customer ? calculateMaxMp(customer.mercenary.baseStats, customer.mercenary.level) : 100;
  const hpPercent = customer ? (customer.mercenary.currentHp / maxHp) * 100 : 100;
  const mpPercent = customer ? (customer.mercenary.currentMp / maxMp) * 100 : 100;

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">

        {/* Layer 0: Background */}
        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('shop_interior.png')} 
                alt="Shop Interior" 
                className="w-full h-full object-cover opacity-80"
                onError={(e) => {
                    e.currentTarget.style.display = 'none';
                    e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)';
                }}
            />
            <div className={`absolute inset-0 transition-colors duration-500 ${!isShopOpen ? 'bg-black/70' : 'bg-black/20'}`}></div>
        </div>

        {/* Layer 1: Main Content */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-center pb-32 pointer-events-none">
            {isShopOpen && (
                <>
                   {customer ? (
                       <div className="flex flex-col items-center animate-in fade-in slide-in-from-right duration-500 relative">

                           {/* Info Card Overlay (Left of Character) */}
                           <div className="absolute top-20 -left-[280px] w-64 bg-stone-900/90 border border-stone-600 rounded-lg p-4 shadow-xl backdrop-blur-md animate-in slide-in-from-left-4 fade-in z-20">
                                <div className="flex items-center gap-3 border-b border-stone-700 pb-3 mb-3">
                                    <div className="w-12 h-12 bg-stone-800 rounded border border-stone-600 overflow-hidden">
                                        <img src={getAssetUrl(customer.mercenary.portraitUrl || 'adventurer_wanderer_01.png')} className="w-full h-full object-cover" />
                                    </div>
                                    <div>
                                        <h3 className="text-amber-100 font-bold leading-tight">{customer.mercenary.name}</h3>
                                        <p className="text-stone-400 text-xs">Level {customer.mercenary.level} {customer.mercenary.job}</p>
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    {/* HP Bar */}
                                    <div>
                                        <div className="flex justify-between text-[10px] text-stone-400 mb-1">
                                            <span className="flex items-center gap-1"><Heart className="w-3 h-3 text-red-500"/> HP</span>
                                            <span>{Math.floor(customer.mercenary.currentHp)}/{maxHp}</span>
                                        </div>
                                        <div className="w-full h-1.5 bg-stone-800 rounded-full overflow-hidden">
                                            <div className="h-full bg-red-600 rounded-full" style={{ width: `${hpPercent}%` }}></div>
                                        </div>
                                    </div>

                                    {/* MP Bar */}
                                    <div>
                                        <div className="flex justify-between text-[10px] text-stone-400 mb-1">
                                            <span className="flex items-center gap-1"><Zap className="w-3 h-3 text-blue-500"/> MP</span>
                                            <span>{Math.floor(customer.mercenary.currentMp)}/{maxMp}</span>
                                        </div>
                                        <div className="w-full h-1.5 bg-stone-800 rounded-full overflow-hidden">
                                            <div className="h-full bg-blue-600 rounded-full" style={{ width: `${mpPercent}%` }}></div>
                                        </div>
                                    </div>

                                    {/* Stats Grid */}
                                    <div className="grid grid-cols-2 gap-2 text-[10px] text-stone-300 pt-2 border-t border-stone-800">
                                        <div className="flex justify-between"><span>STR</span> <span className="text-amber-500">{customer.mercenary.baseStats.strength}</span></div>
                                        <div className="flex justify-between"><span>DEX</span> <span className="text-amber-500">{customer.mercenary.baseStats.dexterity}</span></div>
                                        <div className="flex justify-between"><span>INT</span> <span className="text-amber-500">{customer.mercenary.baseStats.intelligence}</span></div>
                                        <div className="flex justify-between"><span>LUK</span> <span className="text-amber-500">{customer.mercenary.baseStats.luck}</span></div>
                                    </div>

                                    {/* Affinity */}
                                    <div className="pt-2 flex items-center justify-between">
                                        <span className="text-xs text-stone-500">Affinity</span>
                                        <div className="flex">
                                            {[1,2,3,4,5].map(i => (
                                                <Heart key={i} className={`w-3 h-3 ${i <= Math.ceil(customer.mercenary.affinity / 20) ? 'text-pink-500 fill-pink-500' : 'text-stone-700'}`} />
                                            ))}
                                        </div>
                                    </div>
                                </div>
                           </div>

                           {/* Request Bubble */}
                           <div 
                                className="absolute -top-32 -right-20 w-64 h-32 flex items-center justify-center z-50 animate-in zoom-in delay-200 duration-300"
                                style={{
                                    backgroundImage: `url(${getAssetUrl('bubble_thought.png')})`,
                                    backgroundSize: 'contain',
                                    backgroundRepeat: 'no-repeat',
                                    backgroundPosition: 'center'
                                }}
                           >
                               <div className="pb-6 pl-2 flex items-center gap-3">
                                   <div className="bg-amber-100/80 p-1.5 rounded-lg backdrop-blur-sm">
                                        <PackageOpen className="w-6 h-6 text-amber-700" />
                                   </div>
                                   <div className="leading-tight">
                                       <div className="font-bold text-stone-800 text-sm line-clamp-1 w-24">{getItemName(customer.requestedId)}</div>
                                       <div className="text-xs font-bold text-emerald-600 flex items-center gap-0.5">
                                           <Coins className="w-3 h-3" />
                                           {customer.price} G
                                       </div>
                                   </div>
                               </div>
                           </div>

                           {/* Character Sprite */}
                           <div className="relative z-10 filter drop-shadow-2xl">
                               <img 
                                   src={getAssetUrl('adventurer_wanderer_01.png')} 
                                   alt="Adventurer" 
                                   className="h-[60vh] object-contain max-w-none transform translate-y-40"
                                   onError={(e) => {
                                        e.currentTarget.style.display = 'none';
                                        e.currentTarget.parentElement!.innerHTML = '<div class="w-48 h-64 bg-stone-700 rounded-t-full border-4 border-stone-600"></div>';
                                   }}
                               />
                           </div>

                       </div>
                   ) : (
                       <div className="flex flex-col items-center animate-pulse bg-stone-950/60 p-4 rounded-lg backdrop-blur mt-20">
                           <p className="text-stone-400 font-mono">Waiting for customer...</p>
                       </div>
                   )}
                </>
            )}
        </div>

        {/* Layer 2: Counter */}
        <div className="absolute bottom-0 w-full z-20 pointer-events-none">
             <img 
                src={getAssetUrl('shop_counter.png')} 
                alt="Shop Counter" 
                className="w-full object-cover md:h-64"
                onError={(e) => {
                     e.currentTarget.style.display = 'none';
                     e.currentTarget.parentElement!.classList.add('bg-stone-950', 'border-t-8', 'border-stone-800');
                }}
             />
        </div>

        {/* Layer 3: Closed Overlay */}
        {!isShopOpen && (
            <div className="absolute inset-0 flex items-center justify-center z-50">
                <div className="text-center animate-in fade-in zoom-in duration-500 bg-stone-950/90 p-8 rounded-xl border border-stone-700 backdrop-blur-md shadow-2xl">
                    <div className="mb-6 bg-stone-800/80 p-6 rounded-full border-4 border-dashed border-stone-600 inline-block">
                        <Store className="w-16 h-16 text-stone-500" />
                    </div>
                    <h2 className="text-3xl font-bold text-stone-200 mb-2 font-serif">The Shop is Closed</h2>
                    <p className="text-stone-400 mb-8">Open your doors to attract adventurers.</p>

                    <button
                        onClick={handleToggleShop}
                        className="px-8 py-3 bg-amber-700 hover:bg-amber-600 text-amber-50 rounded-lg font-bold text-lg shadow-lg hover:shadow-amber-900/20 transition-all flex items-center gap-2 mx-auto"
                    >
                        <Store className="w-5 h-5" />
                        Open Shop
                    </button>
                </div>
            </div>
        )}

        {/* Layer 4: Dialogue */}
        {isShopOpen && customer && (
            <DialogueBox 
                speaker={customer.mercenary.name}
                text={customer.dialogue}
                options={[
                    {
                        label: `Sell (${customer.price} G)`,
                        action: handleSell,
                        disabled: !hasItem(),
                        variant: 'primary'
                    },
                    {
                        label: "Refuse",
                        action: handleRefuse, 
                        variant: 'neutral'
                    }
                ]}
            />
        )}

    </div>
  );
};

export default ShopTab;
